def merge_within(pairs):
    sorted_pairs = sorted(pairs)
    merged_list = []
    for pair in sorted_pairs:
        if not merged_list or merged_list[-1][1] < pair[0]:  # edge case: starting point of new pair is less than end point of last merged pair
